    } else {
        tip.textContent = '提示:在确认后立刻使用';
    }

    // 按钮容器
    const buttonContainer = docContext.createElement('div');
    buttonContainer.style.cssText = `
        display: flex;
        gap: 10px;
        justify-content: center;
    `;

    // 确认按钮
    const confirmBtn = docContext.createElement('button');
    confirmBtn.textContent = '确认';
    confirmBtn.style.cssText = `
        background-color: #28a745;
        color: white;
        padding: 8px 20px;
        border: none;
        border-radius: 4px;
        cursor: pointer;
        font-size: 14px;
    `;

    // 取消按钮
    const cancelBtn = docContext.createElement('button');
    cancelBtn.textContent = '取消';
    cancelBtn.style.cssText = `
        background-color: #6c757d;
        color: white;
        padding: 8px 20px;
        border: none;
        border-radius: 4px;
        cursor: pointer;
        font-size: 14px;
    `;

    // 验证颜色格式
    function isValidColor(color) {
        const colorRegex = /^#([A-Fa-f0-9]{6}|[A-Fa-f0-9]{3})$/;
        return colorRegex.test(color);
    }

    // 实时验证输入
    input.addEventListener('input', () => {
        const value = input.value.trim();
        if (value && !isValidColor(value)) {
            input.style.borderColor = '#dc3545';
            confirmBtn.disabled = true;
            confirmBtn.style.opacity = '0.5';
        } else {
            input.style.borderColor = '#555';
            confirmBtn.disabled = false;
            confirmBtn.style.opacity = '1';
        }
    });

    // 确认事件
    confirmBtn.onclick = () => {
        const value = input.value.trim();
        if (value && isValidColor(value)) {
            onConfirm(value);
            docContext.body.removeChild(overlay);
        } else {
            showNotification('请输入有效的颜色代码格式（如：#FF0000）', 'error');
        }
    };

    // 取消事件
    cancelBtn.onclick = () => {
        docContext.body.removeChild(overlay);
    };

    // ESC键取消
    const escapeHandler = (e) => {
        if (e.key === 'Escape') {
            docContext.body.removeChild(overlay);
            docContext.removeEventListener('keydown', escapeHandler);
        }
    };
    docContext.addEventListener('keydown', escapeHandler);

    // 点击遮罩取消
    overlay.onclick = (e) => {
        if (e.target === overlay) {
            docContext.body.removeChild(overlay);
        }
    };

    // 阻止对话框点击事件冒泡
    dialog.onclick = (e) => {
        e.stopPropagation();
    };

    // 组装对话框
    buttonContainer.appendChild(confirmBtn);
    buttonContainer.appendChild(cancelBtn);

    dialog.appendChild(title);
    dialog.appendChild(input);
    dialog.appendChild(tip);
    dialog.appendChild(buttonContainer);

    overlay.appendChild(dialog);
    docContext.body.appendChild(overlay);

    // 自动聚焦并选中
    setTimeout(() => {
        input.focus();
        input.select();
    }, 100);
}

