function saveCurrentThemePreset() {
    const currentTheme = detectCurrentTheme();
    const presetName = prompt('请输入预设名称:', currentTheme || '新预设');

    if (!presetName || !presetName.trim()) return;

    const preset = {
        theme: currentTheme,
        settings: getCurrentMultilangSettings(),
        timestamp: new Date().toISOString()
    };
    themePresets[presetName.trim()] = preset;
    saveThemePresets();

    showNotification(`主题预设 "${presetName.trim()}" 已保存！`);
}

function downloadAllPresets() {
    const exportData = {
        version: FONT_PACK_VERSION,
        timestamp: new Date().toISOString(),
        themePresets: themePresets, // 主题预设
        multilangPresets: multilangPresets, // 多语言字体预设
        themeBindings: themeMultilangBindings // 主题绑定关系
    };

    const jsonString = JSON.stringify(exportData, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = docContext.createElement('a');
    a.href = url;
    const date = new Date().toISOString().slice(0, 10);
    a.download = `all-presets-${date}.json`;
    docContext.body.appendChild(a);
    a.click();
    docContext.body.removeChild(a);
    URL.revokeObjectURL(url);

    showNotification('所有预设已导出！包含主题预设和字体预设。');
}

function uploadAllPresets() {
    const fileInput = docContext.createElement('input');
    fileInput.type = 'file';
    fileInput.accept = '.json';
    fileInput.style.display = 'none';

    fileInput.addEventListener('change', (e) => {
        const file = e.target.files[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const data = JSON.parse(e.target.result);

                // 导入主题预设
                if (data.themePresets) {
                    Object.assign(themePresets, data.themePresets);
                    saveThemePresets();
                }

                // 导入多语言字体预设
                if (data.multilangPresets) {
                    Object.assign(multilangPresets, data.multilangPresets);
                    saveMultilangPresets();
                }

                // 导入主题绑定关系
                if (data.themeBindings) {
                    Object.assign(themeMultilangBindings, data.themeBindings);
                    saveThemeMultilangBindings();
                }

                showNotification('所有预设已成功导入！包含主题预设和字体预设。');
                toggleThemePresetManagementPanel(); // 刷新管理面板
            } catch (error) {
                showNotification('导入失败：文件格式错误！', 'error');
                console.error('导入预设失败:', error);
            }
        };
        reader.readAsText(file);

        docContext.body.removeChild(fileInput);
    });

    docContext.body.appendChild(fileInput);
    fileInput.click();
}

// ========= 简化版：多语言字体美化功能 =========

// 生成多语言字体CSS（简化版）
function generateMultilangCSS() {
    if (!state.multilangEnabled) return '';

    let css = '';
    const fontFamilyList = [];

    Object.entries(languageTypes).forEach(([langKey, langConfig]) => {
        const fontFamily = state[langConfig.stateKey];
        const fontUrl = state[langConfig.urlKey];

        if (fontFamily && fontFamily.trim()) {
            let actualFontName = fontFamily;

            if (fontUrl && fontUrl.trim()) {
                const uniqueFontName = `MultiLang-${langKey}-${fontFamily.replace(/\s+/g, '')}`;
                actualFontName = uniqueFontName;

                css += `
                @font-face {
                    font-family: '${uniqueFontName}';
                    src: url('${fontUrl}') format('truetype');
                    unicode-range: ${langConfig.unicodeRange};
                    font-display: swap;
                }
                `;
                console.log(`多语言字体: 为${langConfig.label}创建@font-face规则，字体名称: ${uniqueFontName}`);
            } else {
                const localFont = state.localFonts.find(font => font.fontName === fontFamily);
                if (localFont && localFont.fontDataUrl) {
                    const uniqueFontName = `MultiLang-${langKey}-${fontFamily.replace(/\s+/g, '')}`;
                    actualFontName = uniqueFontName;

                    css += `
                    @font-face {
                        font-family: '${uniqueFontName}';
                        src: url('${localFont.fontDataUrl}') format('truetype');
                        unicode-range: ${langConfig.unicodeRange};
                        font-display: swap;
                    }
                    `;
                    console.log(`多语言字体: 为${langConfig.label}使用本地TTF字体，字体名称: ${uniqueFontName}`);
                } else {
                    // 检测字体来源类型
                    const fontSource = detectFontSource(fontFamily);

                    if (fontSource === 'URL') {
                        // 只有URL类型（格式2、3）才重新创建@font-face
                        const originalUrl = state.fontFamilyUrlMap && state.fontFamilyUrlMap[fontFamily];
                        if (originalUrl) {
                            const uniqueFontName = `MultiLang-${langKey}-${fontFamily.replace(/\s+/g, '')}`;
                            actualFontName = uniqueFontName;

                            css += `
                            @font-face {
                                font-family: '${uniqueFontName}';
                                src: url('${originalUrl}') format('truetype');
                                unicode-range: ${langConfig.unicodeRange};
                                font-display: swap;
                            }
                            `;
                            console.log(`多语言字体: 为${langConfig.label}重新创建带unicode-range的@font-face，字体名称: ${uniqueFontName}`);
                        } else {
                            console.log(`多语言字体: 为${langConfig.label}直接使用字体名称: ${fontFamily} (URL类型但未找到原始URL)`);
                        }
                    } else {
                        // IMPORT类型（格式1、4）和System类型直接使用原字体名称
                        console.log(`多语言字体: 为${langConfig.label}直接使用字体名称: ${fontFamily} (${fontSource}类型)`);
                    }
                }
            }

            fontFamilyList.push(`"${actualFontName}"`);
        }
    });

    if (fontFamilyList.length > 0) {
        css += `
        body, .mes_text, #chat, .message, 
        *:not([class*="fa-"]):not([class*="icon"]):not([class*="material"]) {
            font-family: ${fontFamilyList.join(', ')}, sans-serif !important;
        }

        code, pre, .hljs {
            font-family: ${fontFamilyList.join(', ')}, 'Consolas', 'Monaco', monospace !important;
        }
        `;
    }

    return css;
}

// 应用多语言字体CSS（简化版）
function applyMultilangCSS() {
    let styleElement = docContext.getElementById(MULTILANG_STYLE_ID);

    if (!state.multilangEnabled) {
        if (styleElement) {
            styleElement.remove();
            console.log('Font Manager: 多语言字体美化已禁用');
        }
        return;
    }

    const css = generateMultilangCSS();

    if (!styleElement) {
        styleElement = docContext.createElement('style');
        styleElement.id = MULTILANG_STYLE_ID;
        docContext.head.appendChild(styleElement);
    }

    styleElement.textContent = css;
    console.log('Font Manager: 多语言字体CSS已应用（修复版）');
}

// 保存多语言设置到localStorage
function saveMultilangSettings() {
    try {
        const settings = {
            enabled: state.multilangEnabled,
            fonts: {},
            urls: {}
        };

        Object.entries(languageTypes).forEach(([langKey, langConfig]) => {
            settings.fonts[langKey] = state[langConfig.stateKey];
            settings.urls[langKey] = state[langConfig.urlKey];
        });

        localStorage.setItem(LOCAL_STORAGE_KEY_MULTILANG_FONTS, JSON.stringify(settings));
        console.log('Font Manager: 多语言设置已保存');
    } catch (error) {
        console.error('Font Manager: 保存多语言设置失败:', error);
    }
}

// 从localStorage加载多语言设置
function loadMultilangSettings() {
    try {
        const saved = localStorage.getItem(LOCAL_STORAGE_KEY_MULTILANG_FONTS);
        if (saved) {
            const settings = JSON.parse(saved);
            state.multilangEnabled = settings.enabled || false;

            Object.entries(languageTypes).forEach(([langKey, langConfig]) => {
                state[langConfig.stateKey] = settings.fonts[langKey] || null;
                state[langConfig.urlKey] = settings.urls[langKey] || null;
            });

            console.log('Font Manager: 多语言设置已加载');
        }
    } catch (error) {
        console.error('Font Manager: 加载多语言设置失败:', error);
    }
}

