const saveButton = _createButton('保存', 'font-manager-modal-button theme-header-button theme-header-select-style', () => {
    const selectedTheme = themeSelect.value;
    const selectedPreset = presetSelect.value;

    if (!selectedTheme) {
        showNotification('请先选择主题！', 'warning');
        return;
    }

    if (!selectedPreset) {
        showNotification('请先选择预设字体！', 'warning');
        return;
    }

    // 生成默认绑定名称
    const defaultBindingName = `${selectedTheme}+${selectedPreset}`;

    // 弹窗让用户输入或确认绑定名称
    const bindingName = prompt('请输入主题预设名称:', defaultBindingName);

    if (bindingName === null) return; // 用户取消

    if (!bindingName.trim()) {
        showNotification('主题预设名称不能为空！', 'warning');
        return;
    }

    // 获取选中的多语言预设数据
    const multilangPreset = multilangPresets[selectedPreset];
    if (!multilangPreset) {
        showNotification('所选的多语言预设不存在！', 'error');
        return;
    }

    // 保存主题预设（保存到themePresets中，这样管理面板才能显示）
    const themePreset = {
        theme: selectedTheme,
        settings: multilangPreset, // 复制多语言预设的设置
        timestamp: new Date().toISOString()
    };

    themePresets[bindingName.trim()] = themePreset;
    saveThemePresets();

    // 同时保存绑定关系（用于主题切换时自动应用）
    themeMultilangBindings[selectedTheme] = selectedPreset;
    saveThemeMultilangBindings();

