const CLOUD_FONT_SITES_URL = 'https://sharkpan.xyz/f/YYmVh1/%E5%AD%97%E4%BD%93%E7%BD%91%E7%AB%99.json';

function openRecommendSitesModal() {
    ensureModalStructure();
    modalTitleElement.textContent = '推荐获取字体网站';
    modalBodyElement.innerHTML = '';

    // 显示加载状态
    const loadingDiv = docContext.createElement('div');
    loadingDiv.style.textAlign = 'center';
    loadingDiv.style.padding = '40px';
    loadingDiv.style.color = '#ccc';
    loadingDiv.innerHTML = '正在从云端获取推荐网站数据...';
    modalBodyElement.appendChild(loadingDiv);

    // 从云端获取数据
    fetchRecommendSites()
        .then(sitesData => {
            modalBodyElement.innerHTML = '';
            renderRecommendSites(sitesData);
        })
        .catch(error => {
            console.error('获取推荐网站失败:', error);
            modalBodyElement.innerHTML = '';
        });

    _renderFooterButtons([
        { text: '关闭', className: 'font-manager-modal-button close', onClick: () => renderCombinedMainView() }
    ]);

    modalElement.style.display = 'flex';
}

function fetchRecommendSites() {
    return fetch(CLOUD_FONT_SITES_URL, {
        method: 'GET',
        headers: {
            'Accept': 'application/json',
        }
    })
    .then(response => {
        if (!response.ok) {
            throw new Error(`HTTP ${response.status}: ${response.statusText}`);
        }
        return response.json();
    })
    .catch(error => {
        console.error('云端获取失败:', error);
        throw error;
    });
}

function renderRecommendSites(sitesData) {
    if (!sitesData || !sitesData.websites || !Array.isArray(sitesData.websites)) {
        return;
    }

    const container = docContext.createElement('div');

    // 添加更新时间显示
    if (sitesData.lastUpdated) {
        const updateInfo = docContext.createElement('div');
        updateInfo.style.textAlign = 'center';
        updateInfo.style.marginBottom = '20px';
        updateInfo.style.fontSize = '12px';
        updateInfo.style.color = '#888';
