        container.appendChild(updateInfo);
    }

    // 按分类组织网站
    const categories = {};
    sitesData.websites.forEach(site => {
        const category = site.category || '其他';
        if (!categories[category]) {
            categories[category] = [];
        }
        categories[category].push(site);
    });

    // 渲染每个分类
