    const savedBgColor = localStorage.getItem(LOCAL_STORAGE_KEY_MES_CODE_BG_COLOR);
    const savedTextColor = localStorage.getItem(LOCAL_STORAGE_KEY_MES_CODE_TEXT_COLOR);
    const savedBorderColor = localStorage.getItem(LOCAL_STORAGE_KEY_MES_CODE_BORDER_COLOR);
