    }

    if (savedBorderColor) {
        stylesToApply.borderColor = savedBorderColor;
        state.mesCodeBorderColor = savedBorderColor;
        foundSaved = true;
    } else {
        state.mesCodeBorderColor = null;
    }

    if (savedBackgroundOpacity) {
        stylesToApply.backgroundOpacity = savedBackgroundOpacity;
        state.mesCodeBackgroundOpacity = savedBackgroundOpacity;
        foundSaved = true;
    } else {
        state.mesCodeBackgroundOpacity = null;
    }

    if (savedBackgroundImage) {
        stylesToApply.backgroundImage = savedBackgroundImage;
        state.mesCodeBackgroundImage = savedBackgroundImage;
        foundSaved = true;
    } else {
        state.mesCodeBackgroundImage = null;
