function applyMultilangPreset(presetName, isAutoApply = false) {
    const preset = multilangPresets[presetName];
    if (!preset) {
        showNotification(`预设 "${presetName}" 不存在！`);
        return;
    }

    state.multilangEnabled = preset.enabled || false;

    Object.entries(languageTypes).forEach(([langKey, langConfig]) => {
        if (preset.fonts[langKey]) {
            state[langConfig.stateKey] = preset.fonts[langKey].fontFamily || null;
            state[langConfig.urlKey] = preset.fonts[langKey].fontUrl || null;
        }
    });

    // 设置为多语言应用模式
    state.fontApplicationMode = 'multilang';
    state.singleFontFamily = null;
    localStorage.setItem('fontManagerApplicationMode', 'multilang');
    localStorage.removeItem('fontManagerSingleFont');

    saveMultilangSettings();
    applyMultilangCSS();

    if (isAutoApply) {
        // 自动应用时的特殊提醒
        const currentThemeName = currentTheme || '当前主题';
        showNotification(`已应用主题预设: "${currentThemeName}+${presetName}"`, 'info', '主题绑定字体预设自动切换');
    } else {
        // 手动应用时的普通提醒
        showNotification(`多语言字体预设 "${presetName}" 已应用！`);
    }
}

// ========= 主题预设管理功能 =========
function loadThemePresets() {
    try {
        const saved = localStorage.getItem(LOCAL_STORAGE_KEY_THEME_PRESETS);
        if (saved) {
            themePresets = JSON.parse(saved);
            console.log('Font Manager: 主题预设已加载', themePresets);
        }
    } catch (error) {
        console.error('Font Manager: 加载主题预设失败:', error);
        themePresets = {};
    }
}

function saveThemePresets() {
    try {
        localStorage.setItem(LOCAL_STORAGE_KEY_THEME_PRESETS, JSON.stringify(themePresets));
        console.log('Font Manager: 主题预设已保存');
    } catch (error) {
        console.error('Font Manager: 保存主题预设失败:', error);
    }
}

function detectCurrentTheme() {
    // 优先从SillyTavern的主题选择器获取
    const themeSelector = docContext.getElementById('themes');
    if (themeSelector && themeSelector.value) {
        return themeSelector.value;
    }

    // 备选方案：从CSS链接检测
    const themeElement = docContext.querySelector('link[href*="themes/"]') || 
                        docContext.querySelector('link[href*="theme"]') ||
                        docContext.querySelector('[data-theme]');

    if (themeElement) {
        if (themeElement.href) {
            const themeName = themeElement.href.split('/').pop().replace('.css', '');
            return themeName || 'default';
        } else if (themeElement.dataset.theme) {
            return themeElement.dataset.theme;
        }
    }

    const bodyClass = docContext.body.className;
    const themeMatch = bodyClass.match(/theme-(\w+)/);
    if (themeMatch) {
        return themeMatch[1];
    }

    return 'default';
}

function getCurrentMultilangSettings() {
    const settings = {
        enabled: state.multilangEnabled,
        fonts: {}
    };

    Object.entries(languageTypes).forEach(([langKey, langConfig]) => {
        settings.fonts[langKey] = {
            fontFamily: state[langConfig.stateKey],
            fontUrl: state[langConfig.urlKey]
        };
    });

    return settings;
}

function applyThemePreset(presetName) {
    const preset = themePresets[presetName];
    if (!preset || !preset.settings) {
        showNotification(`主题预设 "${presetName}" 不存在或数据无效！`);
        return;
    }

    const settings = preset.settings;
    state.multilangEnabled = settings.enabled || false;

    Object.entries(languageTypes).forEach(([langKey, langConfig]) => {
        if (settings.fonts[langKey]) {
            state[langConfig.stateKey] = settings.fonts[langKey].fontFamily || null;
            state[langConfig.urlKey] = settings.fonts[langKey].fontUrl || null;
        }
    });

    saveMultilangSettings();
    applyMultilangCSS();
    showNotification(`主题预设 "${presetName}" 已应用！`);
}

function resetToDefaultMultilangState(themeName) {
    // 重置多语言字体设置到默认状态
    state.multilangEnabled = false;

    Object.entries(languageTypes).forEach(([langKey, langConfig]) => {
        state[langConfig.stateKey] = null;
        state[langConfig.urlKey] = null;
    });

    saveMultilangSettings();
    applyMultilangCSS(); // 这会移除多语言CSS，因为multilangEnabled为false

    // 检查当前字体应用模式
    if (state.fontApplicationMode === 'single' && state.singleFontFamily) {
        // 如果是单字体模式，恢复单字体设置
        applyGlobalFontToAllElements(state.singleFontFamily);
        localStorage.setItem(LOCAL_STORAGE_KEY_ACTIVE_FONT, state.singleFontFamily);
        state.activeFont = state.singleFontFamily;
        console.log(`Font Manager: 保持单字体设置: ${state.singleFontFamily}`);
        //showNotification(`主题 "${themeName}" 无绑定字体预设，已清除多语言设置，保持单字体: ${state.singleFontFamily}`, 'info', '主题切换');
    } else {
        // 如果不是单字体模式，重置到默认字体
        resetToDefaultFont();
        state.fontApplicationMode = 'default';
        localStorage.setItem('fontManagerApplicationMode', 'default');
        localStorage.removeItem('fontManagerSingleFont');
        //showNotification(`主题 "${themeName}" 无绑定字体预设，已重置到默认状态`, 'info', '主题切换');
    }
}

// 监听主题变化
function setupThemeChangeObserver() {
    // 直接监听SillyTavern的主题选择器
    const themeSelector = docContext.getElementById('themes');
    if (themeSelector) {
        themeSelector.addEventListener('change', (event) => {
            const newTheme = event.target.value;
            if (newTheme && newTheme !== currentTheme) {
                const bindingPreset = themeMultilangBindings[newTheme];
                if (bindingPreset && multilangPresets[bindingPreset]) {
                    console.log(`检测到主题变化: ${currentTheme} -> ${newTheme}，应用绑定预设: ${bindingPreset}`);
                    currentTheme = newTheme;
                    applyMultilangPreset(bindingPreset, true); // 传入true表示是自动应用
                } else {
                    currentTheme = newTheme;
                    console.log(`主题切换到: ${newTheme}，没有绑定的字体预设，重置到默认状态`);
                    resetToDefaultMultilangState(newTheme);
                }
            }
        });
        console.log('Font Manager: 已设置主题选择器变化监听');
    } else {
        console.warn('Font Manager: 未找到主题选择器，将在延迟后重试');
        // 延迟重试，确保页面完全加载
        setTimeout(() => {
            setupThemeChangeObserver();
        }, 2000);
    }

    // 保留原有的DOM变化监听作为备选方案
    const observer = new MutationObserver((mutations) => {
        mutations.forEach((mutation) => {
            if (mutation.type === 'attributes' && 
                (mutation.attributeName === 'href' || mutation.attributeName === 'data-theme' || mutation.attributeName === 'class')) {
                const newTheme = detectCurrentTheme();
                const bindingPreset = themeMultilangBindings[newTheme];
                if (newTheme !== currentTheme) {
                    if (bindingPreset && multilangPresets[bindingPreset]) {
                        console.log(`通过DOM监听检测到主题变化: ${currentTheme} -> ${newTheme}，应用绑定预设: ${bindingPreset}`);
                        currentTheme = newTheme;
                        applyMultilangPreset(bindingPreset, true);
                    } else {
                        console.log(`通过DOM监听检测到主题变化: ${currentTheme} -> ${newTheme}，没有绑定的字体预设，重置到默认状态`);
                        currentTheme = newTheme;
                        resetToDefaultMultilangState(newTheme);
                    }
                }
            }
        });
    });

    observer.observe(docContext.documentElement, {
        attributes: true,
        subtree: true,
        attributeFilter: ['href', 'data-theme', 'class']
    });

    const links = docContext.querySelectorAll('link');
    links.forEach(link => {
        observer.observe(link, {
            attributes: true,
            attributeFilter: ['href']
        });
    });
}

function deleteAllThemePresets() {
    if (!showConfirmation('确定要删除所有主题预设吗？\n\n这个操作将会：\n- 删除所有已保存的主题预设\n- 清除所有主题与字体预设的绑定关系\n\n注意：字体预设和字体文件不会被删除。\n\n此操作无法撤销！', '删除确认')) {
        return;
    }

    // 清空主题预设
    themePresets = {};
    saveThemePresets();

    // 清空主题绑定关系
    themeMultilangBindings = {};
    saveThemeMultilangBindings();

    showNotification('所有主题预设已删除！', 'success');

    // 刷新管理面板
    toggleThemePresetManagementPanel();
}

// ========= Initialization =========
function initializeFontManager() {
    try {
        const computedStyle = window.getComputedStyle(docContext.documentElement);
        const cssVarValue = computedStyle.getPropertyValue('--mainFontSize').trim();
        if (cssVarValue) {
            const parsed = parseInt(cssVarValue);
            if (!isNaN(parsed)) {
                initialMainFontSizeFromCSS = cssVarValue;
                initialMainFontSizeNumber = parsed;
                console.log('Font Manager: Initial --mainFontSize from CSS:', initialMainFontSizeFromCSS);
            }
        }
    } catch (e) {
        console.warn('Font Manager: Could not read initial --mainFontSize from CSS. Falling back to default.', e);
    }

   try {
        const computedStyle = window.getComputedStyle(docContext.documentElement);
        const cssVarValue = computedStyle.getPropertyValue('--icon-actual-size').trim();
        if (cssVarValue) {
            const parsed = parseInt(cssVarValue);
            if (!isNaN(parsed)) {
                initialIconSizeFromCSS = cssVarValue;
                initialIconSizeNumber = parsed;
                console.log('Font Manager: Initial --icon-actual-size from CSS:', initialIconSizeFromCSS);
            }
        }
    } catch (e) {
        console.warn('Font Manager: Could not read initial --icon-actual-size from CSS. Falling back to default 45px.', e);
    }

    try {
        const computedStyle = window.getComputedStyle(docContext.documentElement);
        const cssVarValue = computedStyle.getPropertyValue('--button-size').trim();
        if (cssVarValue) {
            const parsed = parseInt(cssVarValue);
            if (!isNaN(parsed)) {
                initialButtonSizeFromCSS = cssVarValue;
                initialButtonSizeNumber = parsed;
                console.log('Font Manager: Initial --button-size from CSS:', initialButtonSizeFromCSS);
            }
        }
    } catch (e) {
        console.warn('Font Manager: Could not read initial --button-size from CSS. Falling back to default 32px.', e);
    }

    loadFontsFromStorage();
    loadFontImportUrlsFromStorage();
    loadMultilangSettings();
    // 加载字体应用模式状态
    const savedMode = localStorage.getItem('fontManagerApplicationMode');
    const savedSingleFont = localStorage.getItem('fontManagerSingleFont');
    if (savedMode) {
        state.fontApplicationMode = savedMode;
        if (savedMode === 'single' && savedSingleFont) {
            state.singleFontFamily = savedSingleFont;
        }
    }
    if (state.fontImportUrls && state.fontImportUrls.length > 0) {
        state.fontImportUrls.forEach((url, index) => {
            try {
                const styleElement = docContext.createElement('style');
                styleElement.id = `font-manager-runtime-import-${index}`;
                styleElement.setAttribute('data-font-url', url);
                styleElement.textContent = `@import url('${url}');`;
                docContext.head.appendChild(styleElement);
                console.log('Font Manager: Re-applied @import URL from storage:', url);
            } catch (e) {
                console.error('Font Manager: Error re-applying @import URL ' + url + ' from storage:', e);
            }
        });
    }

    try {
        const activeFont = localStorage.getItem(LOCAL_STORAGE_KEY_ACTIVE_FONT);
        if (activeFont && state.importedFontFamilies.includes(activeFont)) {
            setTimeout(() => {
                docContext.body.style.setProperty('font-family', activeFont, 'important');
                console.log('Font Manager: Last active font applied on load:', activeFont);
            }, 500);
        } else if (activeFont) {
            localStorage.removeItem(LOCAL_STORAGE_KEY_ACTIVE_FONT);
        }
    } catch (e) {
        console.error('Font Manager: Error applying last active font from localStorage:', e);
    }

    try {
        const savedSize = localStorage.getItem(LOCAL_STORAGE_KEY_GLOBAL_FONT_SIZE);
        if (savedSize && !isNaN(parseFloat(savedSize))) {
            applyGlobalFontSize(parseFloat(savedSize)); 
        }
    } catch (e) {
        console.error('Font Manager: Error applying last global font size from localStorage:', e);
    }

    try {
        const savedIconSize = localStorage.getItem(LOCAL_STORAGE_KEY_ICON_SIZE);
        if (savedIconSize && !isNaN(parseFloat(savedIconSize))) {
            applyIconSize(parseFloat(savedIconSize));
        }
    } catch (e) {
        console.error('Font Manager: Error applying last icon size from localStorage:', e);
    }

    try {
        const savedButtonSize = localStorage.getItem(LOCAL_STORAGE_KEY_BUTTON_SIZE);
        if (savedButtonSize && !isNaN(parseFloat(savedButtonSize))) {
            applyButtonSize(parseFloat(savedButtonSize));
        }
    } catch (e) {
        console.error('Font Manager: Error applying last button size from localStorage:', e);
    }

    Object.keys(colorSettings).forEach(key => {
        const setting = colorSettings[key];

        // 加载保存的颜色或使用默认值
        const savedColor = localStorage.getItem(setting.lsKey);
        if (savedColor) {
            state[key + 'Color'] = savedColor;
            applyColorSetting(key, savedColor);
            console.log(`Font Manager: 加载已保存的${setting.label}颜色: ${savedColor}`);
        } else {
            state[key + 'Color'] = setting.initialValue;
            console.log(`Font Manager: 使用默认${setting.label}颜色: ${setting.initialValue}`);
        }
    });

    // 在应用任何样式之前先获取真正的初始样式
    getInitialHljsStyles();

    // 先初始化HLJS设置
    initializeHljsSettings();

    // 延迟初始化消息内联代码设置，确保不会覆盖HLJS
    setTimeout(() => {
        initializeMessageInlineCodeSettings();
    }, 100);

    const savedActiveFont = localStorage.getItem(LOCAL_STORAGE_KEY_ACTIVE_FONT);
    if (savedActiveFont && state.importedFontFamilies.includes(savedActiveFont)) {
        console.log('Attempting to apply saved active font:', savedActiveFont);
        setTimeout(() => {
            applyFontToBody(savedActiveFont);
        }, 700);
    } else if (savedActiveFont) {
        console.log('Saved active font not in current imported list, clearing:', savedActiveFont);
        localStorage.removeItem(LOCAL_STORAGE_KEY_ACTIVE_FONT);
    }

    injectStyles();
    waitForExtensionsMenu();

    loadLocalFontsFromIndexedDB()
        .then(() => {
            if (state.localFonts && state.localFonts.length > 0) {
                console.log(`Font Manager: 从IndexedDB加载了${state.localFonts.length}个本地字体，开始应用到页面`);
                applyLocalFontsToPage();
                console.log('Font Manager: 本地字体已从 IndexedDB 加载并应用');
            } else {
                console.log('Font Manager: 没有从IndexedDB加载到本地字体');
            }
        })
        .catch(error => {
            console.error('Font Manager: 加载持久化存储的本地字体失败:', error);
        });

    if (state.multilangEnabled) {
        console.log('Font Manager: 多语言字体设置已启用');
        applyMultilangCSS();
    } else {
        console.log('Font Manager: 多语言字体设置未启用');
    }

    console.log('Font Manager initialized.');
    setupDynamicContentObserver();

    // 初始化主题预设
    loadThemePresets();
    loadMultilangPresets();
    loadThemeMultilangBindings();

    // 延迟初始化主题检测，确保页面元素完全加载
    setTimeout(() => {
        currentTheme = detectCurrentTheme();
        setupThemeChangeObserver();

        // 检查是否有当前主题的绑定预设
        const bindingPreset = themeMultilangBindings[currentTheme];
        if (bindingPreset && multilangPresets[bindingPreset]) {
            console.log(`发现当前主题 "${currentTheme}" 绑定的预设 "${bindingPreset}"，初始化时应用字体设置`);
            applyMultilangPreset(bindingPreset, false); // 初始化时不显示自动切换提醒
        }
    }, 1000);
}

// ========= 文档加载完成后初始化 =========
if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initializeFontManager);
} else {
    initializeFontManager();
}
